orderCreate.query:
#graphql
  fragment OrderEditShippingLineValidationOrderFields on Order {
    id
    name
    email
    phone
    poNumber
    createdAt
    updatedAt
    closed
    closedAt
    cancelledAt
    cancelReason
    displayFinancialStatus
    displayFulfillmentStatus
    presentmentCurrencyCode
    paymentGatewayNames
    note
    tags
    customAttributes {
      key
      value
    }
    customer {
      id
      email
      displayName
    }
    currentSubtotalLineItemsQuantity
    currentSubtotalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
      presentmentMoney {
        amount
        currencyCode
      }
    }
    currentTotalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
      presentmentMoney {
        amount
        currencyCode
      }
    }
    totalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
      presentmentMoney {
        amount
        currencyCode
      }
    }
    shippingLines(first: 10) {
      nodes {
        id
        title
        code
        source
        originalPriceSet {
          shopMoney {
            amount
            currencyCode
          }
          presentmentMoney {
            amount
            currencyCode
          }
        }
        discountedPriceSet {
          shopMoney {
            amount
            currencyCode
          }
          presentmentMoney {
            amount
            currencyCode
          }
        }
      }
    }
    lineItems(first: 10) {
      nodes {
        id
        title
        name
        quantity
        currentQuantity
        sku
        variantTitle
        originalUnitPriceSet {
          shopMoney {
            amount
            currencyCode
          }
          presentmentMoney {
            amount
            currencyCode
          }
        }
        originalTotalSet {
          shopMoney {
            amount
            currencyCode
          }
          presentmentMoney {
            amount
            currencyCode
          }
        }
        variant {
          id
          title
          sku
        }
      }
    }
  }

  mutation OrderEditShippingLineValidationCreate(
    $order: OrderCreateOrderInput!
    $options: OrderCreateOptionsInput
  ) {
    orderCreate(order: $order, options: $options) {
      order {
        ...OrderEditShippingLineValidationOrderFields
      }
      userErrors {
        field
        message
      }
    }
  }

